SELECT tpf.execute_user
FROM spotter_aegis.test_plan_functional_case tpf

    INNER JOIN spotter_aegis.test_plan tp ON tpf.test_plan_id = tp.id

WHERE tpf.execute_user IS NOT NULL AND tpf.execute_user != ''
AND tpf.last_exec_time IS NOT NULL
AND tpf.last_exec_time >= #{lastExecTimeStart}
AND tpf.last_exec_time <= #{lastExecTimeEnd}

    AND tp.project_id IN

        #{pid}



    AND tpf.execute_user IN

        #{uid}

SELECT COUNT(*)
FROM spotter_aegis.test_plan_functional_case tpf

    INNER JOIN spotter_aegis.test_plan tp ON tpf.test_plan_id = tp.id

WHERE tpf.last_exec_time IS NOT NULL

    AND tpf.last_exec_time >= #{lastExecTimeStart}


    AND tpf.last_exec_time <= #{lastExecTimeEnd}


    AND tp.project_id IN

        #{pid}



    AND tpf.execute_user = #{executeUser}

SELECT COUNT(*)
FROM spotter_aegis.test_plan_functional_case tpf

    INNER JOIN spotter_aegis.test_plan tp ON tpf.test_plan_id = tp.id

WHERE tpf.last_exec_time IS NOT NULL

    AND tpf.last_exec_time >= #{lastExecTimeStart}


    AND tpf.last_exec_time <= #{lastExecTimeEnd}

AND tpf.last_exec_result = 'SUCCESS'

    AND tp.project_id IN

        #{pid}



    AND tpf.execute_user = #{executeUser}
